static getNextTeamPlanBallAvailableString = (team: Team) => {
  if (!team.nextTeamPlan) {
    return '-';
  }
  const max = team.nextTeamPlan.plan.maxBalls + (team.item?.ballAvailableCount ?? 0);
  return max.toLocaleString();
};

static getNextTeamPlanAiCoachAvailableString = (team: Team) => {
  if (!team.nextTeamPlan) {
    return '-';
  }
  const max = team.nextTeamPlan.plan.maxAiCoachs + (team.item?.aiCoachAvailableCount ?? 0);
  return max.toLocaleString();
};

